import logging
import json
import azure.functions as func


app = func.FunctionApp(http_auth_level=func.AuthLevel.ANONYMOUS)


def add_cors_headers(response: func.HttpResponse, origin: str = "*") -> func.HttpResponse:
    """Add CORS headers to the response."""
    headers = dict(response.headers)
    headers["Access-Control-Allow-Origin"] = origin
    headers["Access-Control-Allow-Methods"] = "GET, POST, PUT, DELETE, PATCH, OPTIONS"
    headers["Access-Control-Allow-Headers"] = "Content-Type, Authorization, X-Requested-With, Accept, Origin"
    headers["Access-Control-Allow-Credentials"] = "false"
    headers["Access-Control-Max-Age"] = "86400"

    return func.HttpResponse(
        body=response.get_body(),
        status_code=response.status_code,
        headers=headers,
        mimetype=response.mimetype
    )


def create_response(body: dict, status_code: int = 200) -> func.HttpResponse:
    """Create a JSON response with CORS headers."""
    response = func.HttpResponse(
        body=json.dumps(body),
        status_code=status_code,
        mimetype="application/json"
    )
    return add_cors_headers(response)


def create_error_response(message: str, status_code: int = 400) -> func.HttpResponse:
    """Create an error JSON response with CORS headers."""
    return create_response({"error": message, "success": False}, status_code)


@app.route(route="health", methods=["GET", "OPTIONS"])
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    """Health check endpoint."""
    logging.info("Health check requested.")

    if req.method == "OPTIONS":
        return add_cors_headers(func.HttpResponse(status_code=204))

    return create_response({
        "status": "healthy",
        "message": "API is running",
        "success": True
    })


@app.route(route="items", methods=["GET", "POST", "OPTIONS"])
def items(req: func.HttpRequest) -> func.HttpResponse:
    """CRUD endpoint for items - supports GET (list) and POST (create)."""
    logging.info(f"Items endpoint called with method: {req.method}")

    if req.method == "OPTIONS":
        return add_cors_headers(func.HttpResponse(status_code=204))

    if req.method == "GET":
        search = req.params.get("search", "")
        page = int(req.params.get("page", "1"))
        page_size = int(req.params.get("page_size", "10"))

        sample_items = [
            {"id": 1, "name": "Item 1", "description": "First item"},
            {"id": 2, "name": "Item 2", "description": "Second item"},
            {"id": 3, "name": "Item 3", "description": "Third item"},
        ]

        if search:
            sample_items = [
                item for item in sample_items
                if search.lower() in item["name"].lower() or search.lower() in item["description"].lower()
            ]

        start = (page - 1) * page_size
        end = start + page_size
        paginated_items = sample_items[start:end]

        return create_response({
            "success": True,
            "data": paginated_items,
            "pagination": {
                "page": page,
                "page_size": page_size,
                "total": len(sample_items)
            }
        })

    elif req.method == "POST":
        try:
            req_body = req.get_json()
        except ValueError:
            return create_error_response("Invalid JSON in request body", 400)

        name = req_body.get("name")
        description = req_body.get("description", "")

        if not name:
            return create_error_response("Field 'name' is required", 400)

        new_item = {
            "id": 4,
            "name": name,
            "description": description
        }

        logging.info(f"Created new item: {new_item}")

        return create_response({
            "success": True,
            "data": new_item,
            "message": "Item created successfully"
        }, 201)


@app.route(route="items/{item_id}", methods=["GET", "PUT", "DELETE", "OPTIONS"])
def item_by_id(req: func.HttpRequest) -> func.HttpResponse:
    """CRUD endpoint for a single item - supports GET, PUT, DELETE."""
    logging.info(f"Item by ID endpoint called with method: {req.method}")

    if req.method == "OPTIONS":
        return add_cors_headers(func.HttpResponse(status_code=204))

    item_id = req.route_params.get("item_id")

    try:
        item_id = int(item_id)
    except (ValueError, TypeError):
        return create_error_response("Invalid item ID", 400)

    sample_items = {
        1: {"id": 1, "name": "Item 1", "description": "First item"},
        2: {"id": 2, "name": "Item 2", "description": "Second item"},
        3: {"id": 3, "name": "Item 3", "description": "Third item"},
    }

    if req.method == "GET":
        item = sample_items.get(item_id)
        if not item:
            return create_error_response("Item not found", 404)

        return create_response({
            "success": True,
            "data": item
        })

    elif req.method == "PUT":
        if item_id not in sample_items:
            return create_error_response("Item not found", 404)

        try:
            req_body = req.get_json()
        except ValueError:
            return create_error_response("Invalid JSON in request body", 400)

        name = req_body.get("name")
        description = req_body.get("description")

        if not name:
            return create_error_response("Field 'name' is required", 400)

        updated_item = {
            "id": item_id,
            "name": name,
            "description": description or sample_items[item_id]["description"]
        }

        logging.info(f"Updated item {item_id}: {updated_item}")

        return create_response({
            "success": True,
            "data": updated_item,
            "message": "Item updated successfully"
        })

    elif req.method == "DELETE":
        if item_id not in sample_items:
            return create_error_response("Item not found", 404)

        logging.info(f"Deleted item {item_id}")

        return create_response({
            "success": True,
            "message": f"Item {item_id} deleted successfully"
        })


